script:
test -f reports/delayed-self-check.log || {
  echo '[ERROR] missing delayed report'
  exit 1
}

grep -E '^stage_started_at=.*Z$' reports/delayed-self-check.log >/dev/null || {
  echo '[ERROR] missing stage_started_at instant'
  exit 1
}

grep -E '^job_started_at=.*Z$' reports/delayed-self-check.log >/dev/null || {
  echo '[ERROR] missing job_started_at instant'
  exit 1
}

delay_ms="$(sed -n 's/^delay_ms=//p' reports/delayed-self-check.log)"
test -n "$delay_ms" || {
  echo '[ERROR] missing delay_ms value'
  exit 1
}

if [ "$delay_ms" -lt 5800 ]; then
  echo "[ERROR] delayed verification failed: ${delay_ms}ms"
  exit 1
fi
